function serializeItem(key, item) {
  const parts = [
    `    rangeMin: ${item.rangeMin},`,
    `    rangeMax: ${item.rangeMax},`,
    `    formula: ${JSON.stringify(item.formula)},`,
  ];
  if (item.formulaNote) {
    parts.push(`    formulaNote: ${JSON.stringify(item.formulaNote)},`);
  }
  parts.push(
    `    benchmark: ${JSON.stringify(item.benchmark)},`,
    `    tipHigh: ${JSON.stringify(item.tipHigh)},`,
    `    tipLow: ${JSON.stringify(item.tipLow)},`,
  );
  return `  ${key}: {\n${parts.join('\n')}\n  }`;
}

const content = `/** ${FILE_HEADER} */
export const PLAN_KPI_TOOLTIPS = {
${Object.entries(PLAN_KPI_MESSAGES).map(([key, item]) => serializeItem(key, item)).join(',\n')}
};

function getKpiValueStatus(value, rangeMin, rangeMax) {
  if (value === null || value === undefined || Number.isNaN(value)) return null;
  if (value > rangeMax) return 'high';
  if (value < rangeMin) return 'low';
  return 'ok';
}

export function getPlanKpiTooltip(key, value = null) {
  const item = PLAN_KPI_TOOLTIPS[key];
  if (!item) return '';
  const lines = [\`${LABEL_FORMULA}\`, item.formula];
  if (item.formulaNote) lines.push(item.formulaNote);
  lines.push(\`${LABEL_BENCHMARK}\`, item.benchmark);

  const status = getKpiValueStatus(value, item.rangeMin, item.rangeMax);
  if (status === 'high') lines.push('${STATUS_HIGH}');
  else if (status === 'low') lines.push('${STATUS_LOW}');
  else if (status === 'ok') lines.push('${STATUS_OK}');

  lines.push(
    \`${LABEL_TIPS}\`,
    \`${LABEL_HIGH}\`,
    item.tipHigh,
    \`${LABEL_LOW}\`,
    item.tipLow,
  );
  return lines.join('\\n');
}
`;

writeFileSync(outPath, content, 'utf8');
